let data = [];
let scrape = $input.first().json.data.scrape;
// Loop over input items and add a new field called 'myNewField' to the JSON of each one

Object.entries($input.first().json.data.manual).forEach(([key, value]) => {
  if(key != 'images'){
    data.push({
      label: key.replace("_", " "),
      value: value
    })
  }
});
return {
  data: [...data, ...scrape],
  blogConfig: {
    brandingStyle: $input.first().json.config.branding,
    persona: $input.first().json.config.persona,
    intent: $input.first().json.config.intent,
    internalLink: $input.first().json.config.internalLink,
    existingTitle: $input.first().json.config.title,
    language: $input.first().json.config.language
  }
}

function getValidJsonObject(rawText) {

    if (typeof rawText !== 'string' || rawText.trim() === '') {
        console.error("Invalid input or empty text field.");
        return null;
    }

    let jsonString = rawText.trim();

    // 2. Check for and remove the markdown JSON block fences.
    // This regex is robust and handles variations in whitespace.
    const markdownRegex = /^```json\s*([\s\S]*?)\s*```$/;
    const match = jsonString.match(markdownRegex);

    if (match) {
        // If it's a match, the actual JSON string is in the first capture group.
        jsonString = match[1];
    }

    // 3. Parse the cleaned string into a JSON object.
    try {
        return JSON.parse(jsonString);
    } catch (error) {
        console.error("Failed to parse JSON string:", error);
        console.error("Problematic string:", jsonString);
        return null;
    }
}
return getValidJsonObject($input.first().json.content.parts[0].text);

return{
  desc: $input.first().json.content.parts[0].text,
  url: $('Loop Over Items').first().json.url,
  binary: $('Loop Over Items').first().json.binary,
  mime: $('Loop Over Items').first().json.mime
}

let description = '';
let n = 1;
for (const item of $input.first().json.parsed) {
  description += 'Description of image '+n+':\n\r'+item.desc+'\n\r';
  n++
}

return {
  desc: description+'\n\r'+ 'Target Prompt:\n\r'+$input.first().json.prompt
}

const result = JSON.parse($input.first().json.content.parts[0].text);

const prompt = result.final_prompt;

// Prepare the parts array with the text prompt first
const parts = [
  { text: prompt }
];

// Loop through all incoming items and extract images
// Note: If all images are in one item as different binary keys, adjust the loop.
// This assumes multiple items (e.g., 3 separate image items).
let x = 1;
for (const item of $('Prepare Image').first().json.parsed) {
  if (!result.excluded_images.includes(x)) {
parts.push({
      inlineData: {
        mimeType: item.mime,
        data: item.binary // n8n already provides this as base64
      }
    });
  }
 x++;
}

// Return the structure ready for the API
return {
  json: {
    payload: {
      contents: [
        {
          parts: parts
        }
      ],
      generationConfig: {
          responseModalities: ["image"],
          topP: 0.2,
          imageConfig:{
               aspectRatio: "16:9"
          }
      }
    }
  }
};

